// Validate classification output against schema - process ALL items
const items = $input.all();
const validTopics = ['bitcoin', 'zk', 'censorship-resistance', 'comms', 'payments', 'identity', 'privacy', 'surveillance', 'activism', 'sovereignty'];

return items.map(item => {
  const data = item.json;
  const classification = data.classification;
  const errors = [];

  // Validate topics
  if (!Array.isArray(classification.topics)) {
    errors.push('topics must be an array');
  } else {
    if (classification.topics.length < 1) errors.push('topics must have at least 1 item');
    if (classification.topics.length > 5) errors.push('topics must have at most 5 items');
    for (const topic of classification.topics) {
      if (!validTopics.includes(topic)) {
        errors.push(`Invalid topic: ${topic}. Must be one of: ${validTopics.join(', ')}`);
      }
    }
  }

  // Validate scores
  if (typeof classification.freedom_relevance_score !== 'number' || classification.freedom_relevance_score < 0 || classification.freedom_relevance_score > 100) {
    errors.push('freedom_relevance_score must be an integer between 0 and 100');
  }
  if (typeof classification.credibility_score !== 'number' || classification.credibility_score < 0 || classification.credibility_score > 100) {
    errors.push('credibility_score must be an integer between 0 and 100');
  }

  // Validate geo
  if (!Array.isArray(classification.geo)) {
    errors.push('geo must be an array');
  }

  // Log validation result
  if (errors.length > 0) {
    console.log('Classification validation errors:', errors);
  }

  return {
    json: {
      ...data,
      _validationErrors: errors,
      _validationPassed: errors.length === 0
    }
  };
});

// Check if content meets relevance threshold from config - process ALL items
const items = $input.all();

return items.map(item => {
  const data = item.json;
  const thresholds = data._thresholds || {};
  const relevanceThreshold = thresholds.ingestion?.relevance_threshold || 50;

  const score = data.classification.freedom_relevance_score;

  // Content meets threshold if score >= config threshold
  const meetsThreshold = score >= relevanceThreshold;

  // Pass through all data including _agents
  return {
    json: {
      ...data,
      meetsThreshold,
      usedThreshold: relevanceThreshold
    }
  };
});

