// Process real Claude API responses and match with source data by index
const claudeResponses = $input.all();
const applyThresholdItems = $('Apply Threshold').all();

// Match responses with their source data by index
return claudeResponses.map((response, index) => {
  const claudeResponse = response.json;
  // Use index matching - items flow through in order
  const applyThresholdData = applyThresholdItems[index]?.json || applyThresholdItems[0]?.json || {};

  return {
    json: {
      content: claudeResponse.content,
      _sourceItemId: applyThresholdData.sourceItemId,
      _classification: applyThresholdData.classification,
      _sourceItemUrl: applyThresholdData.sourceItemUrl,
      _thresholds: applyThresholdData._thresholds,
      _agents: applyThresholdData._agents
    }
  };
});

// Parse summary and determine publish status using thresholds from config - process ALL items
const items = $input.all();

return items.map(item => {
  const input = item.json;
  const thresholds = input._thresholds || {};
  const classification = input._classification;
  let summary;
  let parseError = null;

  try {
    let text = input.content[0].text;

    // Strip markdown code blocks if present (Claude often wraps JSON in ```json...```)
    text = text.trim();
    if (text.startsWith('```')) {
      // Remove opening fence (```json or ```)
      text = text.replace(/^```(?:json)?\s*\n?/, '');
      // Remove closing fence
      text = text.replace(/\n?```\s*$/, '');
    }

    summary = JSON.parse(text.trim());

    // Ensure citations array exists and includes source URL as fallback
    if (!summary.citations || !Array.isArray(summary.citations)) {
      summary.citations = [];
    }
    // Always include source URL if not already present
    if (input._sourceItemUrl && !summary.citations.includes(input._sourceItemUrl)) {
      summary.citations.push(input._sourceItemUrl);
    }
  } catch (e) {
    parseError = e.message;
    console.log('Parse Summary error:', e.message);
    console.log('Source URL:', input._sourceItemUrl);
    console.log('Raw text (first 500 chars):', input.content?.[0]?.text?.substring(0, 500));

    // Create fallback summary with source URL as citation so it can still be published
    summary = {
      title: `[Parse Error] Content from ${input._sourceItemUrl?.split('/').pop() || 'unknown'}`,
      tldr: `Failed to parse AI summary. Original source: ${input._sourceItemUrl}. Error: ${e.message}`,
      summary_bullets: [
        'AI summary parsing failed',
        'Manual review required',
        `Source: ${input._sourceItemUrl}`,
        `Topics: ${classification?.topics?.join(', ') || 'unknown'}`,
        `Relevance: ${classification?.freedom_relevance_score || 'unknown'}`
      ],
      citations: input._sourceItemUrl ? [input._sourceItemUrl] : [],
      deep_dive_markdown: null
    };
  }

  // Get thresholds from config
  const autoPublishRelevance = thresholds.publishing?.auto_publish_relevance || 70;
  const autoPublishCredibility = thresholds.publishing?.auto_publish_credibility || 60;

  // Determine publish status based on gates from config
  // Auto-publish: relevance >= config threshold AND credibility >= config threshold AND has citations AND no parse error
  const hasCitations = summary.citations && summary.citations.length > 0;
  const meetsRelevance = classification.freedom_relevance_score >= autoPublishRelevance;
  const meetsCredibility = classification.credibility_score >= autoPublishCredibility;
  const noParseFail = !parseError;

  const canAutoPublish = meetsRelevance && meetsCredibility && hasCitations && noParseFail;

  const status = canAutoPublish ? 'published' : 'queued';
  const publishedAt = canAutoPublish ? new Date().toISOString() : null;

  // Generate slug from title for URL
  const slug = summary.title
    .toLowerCase()
    .replace(/[^a-z0-9]+/g, '-')
    .replace(/^-|-$/g, '')
    .substring(0, 60);

  const publishedUrl = canAutoPublish 
    ? `https://libertas.fgu.tech/posts/${slug}`
    : null;

  // Detailed logging for debugging publish decisions
  const publishDecision = {
    relevance: `${classification.freedom_relevance_score} >= ${autoPublishRelevance} = ${meetsRelevance}`,
    credibility: `${classification.credibility_score} >= ${autoPublishCredibility} = ${meetsCredibility}`,
    citations: `${summary.citations?.length || 0} > 0 = ${hasCitations}`,
    parseOk: noParseFail,
    result: status
  };
  console.log(`Publish decision for ${input._sourceItemUrl}:`, JSON.stringify(publishDecision));

  return {
    json: {
      sourceItemId: input._sourceItemId,
      sourceItemUrl: input._sourceItemUrl,
      title: summary.title,
      tldr: summary.tldr,
      summaryBullets: summary.summary_bullets,
      deepDiveMarkdown: summary.deep_dive_markdown,
      topics: classification.topics,
      geo: classification.geo,
      freedomRelevanceScore: classification.freedom_relevance_score,
      credibilityScore: classification.credibility_score,
      citations: summary.citations,
      status,
      publishedUrl,
      publishedAt,
      parseError,
      _thresholds: thresholds,
      _usedThresholds: {
        autoPublishRelevance,
        autoPublishCredibility
      },
      _publishDecision: publishDecision
    }
  };
});

