  // Validate topics
  if (!Array.isArray(data.topics)) {
    errors.push('topics must be an array');
  } else {
    for (const topic of data.topics) {
      if (!validTopics.includes(topic)) {
        errors.push(`Invalid topic: ${topic}`);
      }
    }
  }

  // Validate scores
  if (typeof data.freedomRelevanceScore !== 'number' || data.freedomRelevanceScore < 0 || data.freedomRelevanceScore > 100) {
    errors.push('freedomRelevanceScore must be an integer between 0 and 100');
  }
  if (typeof data.credibilityScore !== 'number' || data.credibilityScore < 0 || data.credibilityScore > 100) {
    errors.push('credibilityScore must be an integer between 0 and 100');
  }

  // Validate citations
  if (!Array.isArray(data.citations)) {
    errors.push('citations must be an array');
  }

  // Validate status
  if (!validStatuses.includes(data.status)) {
    errors.push(`status must be one of: ${validStatuses.join(', ')}`);
  }

  // Log validation result
  if (errors.length > 0) {
    console.log('Summary validation errors:', errors);
  }

  return {
    json: {
      ...data,
      _summaryValidationErrors: errors,
      _summaryValidationPassed: errors.length === 0
    }
  };
});

// Build complete INSERT query with proper escaping - process ALL items
const items = $input.all();

function escapeStr(str) {
  if (str === null || str === undefined) return 'NULL';
  // Escape single quotes by doubling them
  return "'" + String(str).replace(/'/g, "''") + "'";
}

function formatPgArray(arr) {
  if (!arr || arr.length === 0) return "'{}'";
  const escaped = arr.map(s => '"' + String(s).replace(/"/g, '\\"').replace(/'/g, "''") + '"');
  return "'{" + escaped.join(',') + "}'";
}

function formatUuidArray(arr) {
  if (!arr || arr.length === 0) return "'{}'";
  return "'{" + arr.join(',') + "}'";
}

return items.map(item => {
  const data = item.json;

