} catch (e) {
  summary = {
    title: `[Parse Error] Community Story`,
    tldr: `Failed to parse AI summary. Error: ${e.message}`,
    summary_bullets: ['AI summary parsing failed', 'Manual review required'],
    citations: input._sourceItemUrl ? [input._sourceItemUrl] : [],
    deep_dive_markdown: null
  };
}

const autoPublishRelevance = thresholds.publishing?.auto_publish_relevance || 70;
const autoPublishCredibility = thresholds.publishing?.auto_publish_credibility || 60;
const hasCitations = summary.citations && summary.citations.length > 0;
const meetsRelevance = classification.freedom_relevance_score >= autoPublishRelevance;
const meetsCredibility = classification.credibility_score >= autoPublishCredibility;
const canAutoPublish = meetsRelevance && meetsCredibility && hasCitations;
const status = canAutoPublish ? 'published' : 'queued';
const publishedAt = canAutoPublish ? new Date().toISOString() : null;

const slug = summary.title.toLowerCase().replace(/[^a-z0-9]+/g, '-').replace(/^-|-$/g, '').substring(0, 60);
const publishedUrl = canAutoPublish ? `https://libertas.fgu.tech/posts/${slug}` : null;

return [{
  json: {
    sourceItemId: input._sourceItemId,
    sourceItemUrl: input._sourceItemUrl,
    title: summary.title,
    tldr: summary.tldr,
    summaryBullets: summary.summary_bullets,
    deepDiveMarkdown: summary.deep_dive_markdown,
    topics: classification.topics,
    geo: classification.geo,
    freedomRelevanceScore: classification.freedom_relevance_score,
    credibilityScore: classification.credibility_score,
    citations: summary.citations,
    status,
    publishedUrl,
    publishedAt,
    _thresholds: thresholds,
    _isUserStory: true,
    _userStoryId: input._userStoryId
  }
}];

// Build INSERT query for user story insight
const data = $input.first().json;

function escapeStr(str) {
  if (str === null || str === undefined) return 'NULL';
  return "'" + String(str).replace(/'/g, "''") + "'";
}

function formatPgArray(arr) {
  if (!arr || arr.length === 0) return "'{}'";
  const escaped = arr.map(s => '"' + String(s).replace(/"/g, '\\\"').replace(/'/g, "''") + '"');
  return "'{" + escaped.join(',') + "}'";
}

// Use sourceItemId (which is user_story_items.id) but note it's not a source_items reference
// We store it for traceability but the FK constraint only applies to source_items
// For user stories, we'll store the user_story_items.id in metadata instead
const query = `INSERT INTO insights (
  source_item_ids, title, tldr, summary_bullets, deep_dive_markdown,
  topics, geo, freedom_relevance_score, credibility_score, citations,
  status, published_url, published_at
) VALUES (
  '{}',
  ${escapeStr(data.title || 'Untitled')},
  ${escapeStr(data.tldr || '')},
  ${formatPgArray(data.summaryBullets || [])},
  ${data.deepDiveMarkdown ? escapeStr(data.deepDiveMarkdown) : 'NULL'},
  ${formatPgArray(data.topics || [])},
  ${formatPgArray(data.geo || [])},
  ${data.freedomRelevanceScore},
  ${data.credibilityScore},
  ${formatPgArray(data.citations || [])},
  ${escapeStr(data.status)},
  ${data.publishedUrl ? escapeStr(data.publishedUrl) : 'NULL'},
  ${data.publishedAt ? escapeStr(data.publishedAt) : 'NULL'}
) RETURNING id, title, status`;

return [{ json: { query, sourceData: data } }];

// Get the insight ID from the insert result and prepare to update user_story_items
const insertResult = $input.first().json;
const sourceData = $('Build User Story Insight Query').first().json.sourceData;

return [{
  json: {
    insightId: insertResult.id,
    userStoryId: sourceData._userStoryId,
    title: insertResult.title,
    status: insertResult.status,
    _thresholds: sourceData._thresholds
  }
}];

// Collect user story processing results and continue to loop
const result = $('Prepare User Story Update').first().json;
console.log(`User story ${result.userStoryId} generated insight ${result.insightId} with status ${result.status}`);
return [{ json: { processed: true, ...result } }];

// User story processing complete, continue to feed publishing
console.log('=== User Story Processing Complete ===');
const items = $input.all();
console.log(`Processed ${items.length} user stories`);
return [{ json: { userStoriesProcessed: items.length } }];

// No pending user stories to process
console.log('No pending user stories to process');
return [{ json: { userStoriesProcessed: 0 } }];

// Evaluate duplicate check result and merge with original data
// Must match each Postgres result with its corresponding original item by index
// Route _skip items to the duplicate path (isNew=false) to bypass processing
const duplicateResults = $input.all();
const originalItems = $('Compute Hash').all();

// Process each item, matching by index
return duplicateResults.map((result, index) => {
  const originalData = originalItems[index]?.json || {};

  // Route _skip items to duplicate path (bypasses classification/summarization)
  if (originalData._skip) {
    return {
      json: {
        ...originalData,
        isNew: false,
        skippedReason: originalData.error || originalData.noItems ? 'source_error' : 'skip_flag'
      }
    };
  }

  // Postgres returns object with id if duplicate found, empty/undefined otherwise
  const isDuplicate = result.json && result.json.id;

  return {
    json: {
      ...originalData,
      isNew: !isDuplicate,
      duplicateId: isDuplicate ? result.json.id : null
    }
  };
});
